from __future__ import annotations

from pathlib import Path

ROOT = Path(__file__).resolve().parents[2]

SETUP_SCRIPT = 'from __future__ import annotations\n\nimport argparse\nimport json\nfrom botocore.exceptions import ClientError\n\nBATCH_VERSION = "batch56a-s3-media-storage-setup"\nDEFAULT_BUCKET = "rsa-cms-media-537765358118-ap-southeast-1"\nDEFAULT_REGION = "ap-southeast-1"\nPOLICY_NAME = "rsa-cms-media-s3-access"\n\n\ndef s3_client(region: str):\n    import boto3\n    return boto3.client("s3", region_name=region)\n\n\ndef iam_client(region: str):\n    import boto3\n    return boto3.client("iam", region_name=region)\n\n\ndef bucket_exists(client, bucket_name: str) -> tuple[bool, str]:\n    try:\n        client.head_bucket(Bucket=bucket_name)\n        return True, "exists"\n    except ClientError as exc:\n        code = str(exc.response.get("Error", {}).get("Code", ""))\n        if code in {"404", "NoSuchBucket", "NotFound"}:\n            return False, "missing"\n        if code in {"403", "AccessDenied"}:\n            raise SystemExit(\n                f"Bucket {bucket_name} exists or is not accessible with the current AWS identity. "\n                "Choose a different bucket name or verify ownership/permissions."\n            ) from exc\n        raise\n\n\ndef create_bucket_if_missing(client, bucket_name: str, region: str, execute: bool) -> None:\n    exists, _ = bucket_exists(client, bucket_name)\n    if exists:\n        print(f"[ok] bucket already exists: {bucket_name}")\n        return\n\n    if not execute:\n        print(f"[dry-run] would create private S3 bucket: {bucket_name} in {region}")\n        return\n\n    print(f"[apply] creating private S3 bucket: {bucket_name} in {region}")\n    if region == "us-east-1":\n        client.create_bucket(Bucket=bucket_name)\n    else:\n        client.create_bucket(\n            Bucket=bucket_name,\n            CreateBucketConfiguration={"LocationConstraint": region},\n        )\n    waiter = client.get_waiter("bucket_exists")\n    waiter.wait(Bucket=bucket_name)\n    print(f"[ok] bucket created: {bucket_name}")\n\n\ndef put_public_access_block(client, bucket_name: str, execute: bool) -> None:\n    config = {\n        "BlockPublicAcls": True,\n        "IgnorePublicAcls": True,\n        "BlockPublicPolicy": True,\n        "RestrictPublicBuckets": True,\n    }\n    if not execute:\n        print("[dry-run] would enable S3 Block Public Access on bucket")\n        return\n    client.put_public_access_block(Bucket=bucket_name, PublicAccessBlockConfiguration=config)\n    print("[ok] S3 Block Public Access enabled")\n\n\ndef put_ownership_controls(client, bucket_name: str, execute: bool) -> None:\n    controls = {"Rules": [{"ObjectOwnership": "BucketOwnerEnforced"}]}\n    if not execute:\n        print("[dry-run] would set object ownership to BucketOwnerEnforced")\n        return\n    client.put_bucket_ownership_controls(Bucket=bucket_name, OwnershipControls=controls)\n    print("[ok] object ownership set to BucketOwnerEnforced")\n\n\ndef put_encryption(client, bucket_name: str, execute: bool) -> None:\n    encryption = {\n        "Rules": [\n            {\n                "ApplyServerSideEncryptionByDefault": {"SSEAlgorithm": "AES256"},\n                "BucketKeyEnabled": False,\n            }\n        ]\n    }\n    if not execute:\n        print("[dry-run] would enable default SSE-S3 encryption")\n        return\n    client.put_bucket_encryption(Bucket=bucket_name, ServerSideEncryptionConfiguration=encryption)\n    print("[ok] default SSE-S3 encryption enabled")\n\n\ndef put_versioning_suspended(client, bucket_name: str, execute: bool) -> None:\n    if not execute:\n        print("[dry-run] would keep bucket versioning suspended/off")\n        return\n    client.put_bucket_versioning(Bucket=bucket_name, VersioningConfiguration={"Status": "Suspended"})\n    print("[ok] bucket versioning suspended/off for Free-Tier-first launch")\n\n\ndef put_tags(client, bucket_name: str, execute: bool) -> None:\n    tags = {\n        "TagSet": [\n            {"Key": "Project", "Value": "rsa-cms"},\n            {"Key": "Batch", "Value": "56A"},\n            {"Key": "Purpose", "Value": "admin-media-uploads"},\n            {"Key": "ManagedBy", "Value": "rsa-cms-script"},\n        ]\n    }\n    if not execute:\n        print("[dry-run] would apply project/cost tags to bucket")\n        return\n    client.put_bucket_tagging(Bucket=bucket_name, Tagging=tags)\n    print("[ok] project/cost tags applied")\n\n\ndef build_role_policy(bucket_name: str) -> dict:\n    return {\n        "Version": "2012-10-17",\n        "Statement": [\n            {\n                "Sid": "RsaCmsMediaBucketReadLocation",\n                "Effect": "Allow",\n                "Action": ["s3:GetBucketLocation", "s3:ListBucket"],\n                "Resource": f"arn:aws:s3:::{bucket_name}",\n            },\n            {\n                "Sid": "RsaCmsMediaObjectAccess",\n                "Effect": "Allow",\n                "Action": ["s3:GetObject", "s3:PutObject", "s3:DeleteObject"],\n                "Resource": f"arn:aws:s3:::{bucket_name}/*",\n            },\n        ],\n    }\n\n\ndef attach_role_policy(role_name: str, bucket_name: str, region: str, execute: bool) -> None:\n    policy = build_role_policy(bucket_name)\n    print("[info] IAM inline policy document:")\n    print(json.dumps(policy, indent=2))\n    if not role_name:\n        print("[skip] no --role-name supplied; IAM role policy was not attached")\n        return\n    if not execute:\n        print(f"[dry-run] would attach inline IAM policy {POLICY_NAME} to role {role_name}")\n        return\n    client = iam_client(region)\n    client.put_role_policy(\n        RoleName=role_name,\n        PolicyName=POLICY_NAME,\n        PolicyDocument=json.dumps(policy),\n    )\n    print(f"[ok] attached inline IAM policy {POLICY_NAME} to role {role_name}")\n\n\ndef main() -> None:\n    parser = argparse.ArgumentParser(description="Batch 56A S3 media bucket and IAM setup")\n    parser.add_argument("--bucket-name", default=DEFAULT_BUCKET)\n    parser.add_argument("--region", default=DEFAULT_REGION)\n    parser.add_argument("--role-name", default="", help="Optional EC2 instance role name to receive S3 access policy")\n    parser.add_argument("--execute", action="store_true", help="Actually create/update AWS resources. Omit for dry-run.")\n    parser.add_argument("--attach-role-policy", action="store_true", help="Attach inline IAM policy to --role-name. Requires --execute.")\n    args = parser.parse_args()\n\n    print("RSA CMS / Mini-CRM Batch 56A S3 media storage setup")\n    print(f"version: {BATCH_VERSION}")\n    print(f"bucket_name: {args.bucket_name}")\n    print(f"region: {args.region}")\n    print(f"mode: {\'EXECUTE\' if args.execute else \'DRY RUN\'}")\n    print("No AWS access keys or secrets are printed by this script.")\n\n    client = s3_client(args.region)\n    create_bucket_if_missing(client, args.bucket_name, args.region, args.execute)\n    put_public_access_block(client, args.bucket_name, args.execute)\n    put_ownership_controls(client, args.bucket_name, args.execute)\n    put_encryption(client, args.bucket_name, args.execute)\n    put_versioning_suspended(client, args.bucket_name, args.execute)\n    put_tags(client, args.bucket_name, args.execute)\n\n    if args.attach_role_policy:\n        if not args.role_name:\n            raise SystemExit("--attach-role-policy requires --role-name")\n        attach_role_policy(args.role_name, args.bucket_name, args.region, args.execute)\n    else:\n        attach_role_policy("", args.bucket_name, args.region, False)\n\n    if not args.execute:\n        print("[done] dry-run complete. Re-run with --execute to apply bucket settings.")\n    else:\n        print("[done] batch56a-s3-media-storage-setup applied.")\n        print("[done] Private S3 bucket setup complete. No public bucket policy, CloudFront, Route 53, versioning, or paid notification service was added.")\n\n\nif __name__ == "__main__":\n    main()\n'

CHECK_SCRIPT = 'from __future__ import annotations\n\nimport argparse\nimport json\nimport secrets\nfrom botocore.exceptions import ClientError\n\nBATCH_VERSION = "batch56a-s3-media-storage-setup"\nDEFAULT_BUCKET = "rsa-cms-media-537765358118-ap-southeast-1"\nDEFAULT_REGION = "ap-southeast-1"\n\n\ndef s3_client(region: str):\n    import boto3\n    return boto3.client("s3", region_name=region)\n\n\ndef check_bucket(client, bucket_name: str) -> int:\n    issues = 0\n    try:\n        client.head_bucket(Bucket=bucket_name)\n        print(f"bucket_exists: True ({bucket_name})")\n    except ClientError as exc:\n        print(f"bucket_exists: False ({exc.response.get(\'Error\', {}).get(\'Code\')})")\n        return issues + 1\n\n    try:\n        public_access = client.get_public_access_block(Bucket=bucket_name)["PublicAccessBlockConfiguration"]\n        print("public_access_block:", json.dumps(public_access, sort_keys=True))\n        expected = ["BlockPublicAcls", "IgnorePublicAcls", "BlockPublicPolicy", "RestrictPublicBuckets"]\n        if not all(public_access.get(key) is True for key in expected):\n            print("FAIL: all S3 Block Public Access settings must be true")\n            issues += 1\n    except ClientError as exc:\n        print(f"FAIL: could not read public access block: {exc.response.get(\'Error\', {}).get(\'Code\')}")\n        issues += 1\n\n    try:\n        encryption = client.get_bucket_encryption(Bucket=bucket_name)["ServerSideEncryptionConfiguration"]\n        print("encryption:", json.dumps(encryption, sort_keys=True))\n        rules = encryption.get("Rules", [])\n        if not any(rule.get("ApplyServerSideEncryptionByDefault", {}).get("SSEAlgorithm") == "AES256" for rule in rules):\n            print("FAIL: bucket should use default SSE-S3 AES256 encryption")\n            issues += 1\n    except ClientError as exc:\n        print(f"FAIL: could not read bucket encryption: {exc.response.get(\'Error\', {}).get(\'Code\')}")\n        issues += 1\n\n    try:\n        ownership = client.get_bucket_ownership_controls(Bucket=bucket_name)["OwnershipControls"]\n        print("ownership_controls:", json.dumps(ownership, sort_keys=True))\n    except ClientError as exc:\n        print(f"WARN: could not read ownership controls: {exc.response.get(\'Error\', {}).get(\'Code\')}")\n\n    try:\n        versioning = client.get_bucket_versioning(Bucket=bucket_name)\n        print("versioning_status:", versioning.get("Status", "Off/Suspended"))\n        if versioning.get("Status") == "Enabled":\n            print("WARN: versioning is enabled; Free-Tier-first launch recommended off/suspended")\n    except ClientError as exc:\n        print(f"WARN: could not read versioning: {exc.response.get(\'Error\', {}).get(\'Code\')}")\n\n    return issues\n\n\ndef write_test(client, bucket_name: str) -> int:\n    key = f"_rsa56a-write-test/{secrets.token_hex(8)}.txt"\n    body = b"rsa cms batch56a s3 write/read/delete test\\n"\n    try:\n        client.put_object(Bucket=bucket_name, Key=key, Body=body, ContentType="text/plain")\n        response = client.get_object(Bucket=bucket_name, Key=key)\n        read_back = response["Body"].read()\n        client.delete_object(Bucket=bucket_name, Key=key)\n        print("write_read_delete_test: PASSED")\n        if read_back != body:\n            print("FAIL: read content did not match written content")\n            return 1\n        return 0\n    except ClientError as exc:\n        print(f"write_read_delete_test: FAILED ({exc.response.get(\'Error\', {}).get(\'Code\')})")\n        return 1\n\n\ndef main() -> None:\n    parser = argparse.ArgumentParser(description="Batch 56A S3 media bucket preflight/check")\n    parser.add_argument("--bucket-name", default=DEFAULT_BUCKET)\n    parser.add_argument("--region", default=DEFAULT_REGION)\n    parser.add_argument("--write-test", action="store_true", help="Put/get/delete a temporary object to verify permissions")\n    args = parser.parse_args()\n\n    print("RSA CMS / Mini-CRM Batch 56A S3 media storage check")\n    print(f"version: {BATCH_VERSION}")\n    print(f"bucket_name: {args.bucket_name}")\n    print(f"region: {args.region}")\n    print("No AWS access keys or secrets are printed by this script.")\n\n    client = s3_client(args.region)\n    issues = check_bucket(client, args.bucket_name)\n    if args.write_test:\n        issues += write_test(client, args.bucket_name)\n\n    if issues:\n        raise SystemExit(f"Batch 56A S3 media storage check FAILED with {issues} issue(s).")\n    print("Batch 56A S3 media storage check PASSED.")\n\n\nif __name__ == "__main__":\n    main()\n'

EC2_ENV_PS1 = 'param(\n    [Parameter(Mandatory = $true)]\n    [string]$KeyPath,\n\n    [Parameter(Mandatory = $true)]\n    [string]$HostName,\n\n    [string]$SshUser = "ubuntu",\n    [string]$BucketName = "rsa-cms-media-537765358118-ap-southeast-1",\n    [string]$Region = "ap-southeast-1",\n    [string]$MaxUploadMb = "5"\n)\n\n$ErrorActionPreference = "Stop"\n\nWrite-Host "RSA CMS Batch 56A - Configure EC2 backend media S3 runtime env"\nWrite-Host "Target: $SshUser@$HostName"\nWrite-Host "Bucket: $BucketName"\nWrite-Host "Region: $Region"\nWrite-Host "No AWS keys are written. EC2 must use its instance profile role."\n\nif (!(Test-Path $KeyPath)) {\n    throw "Key file not found: $KeyPath"\n}\n\n$remoteScript = @\'\nset -euo pipefail\nENV_FILE=/opt/rsa-cms/runtime/backend.env\nBACKUP=/opt/rsa-cms/runtime/backend.env.batch56a-s3.$(date -u +%Y%m%d%H%M%S).bak\nsudo test -f "$ENV_FILE"\nsudo cp "$ENV_FILE" "$BACKUP"\necho "backup_created: $BACKUP"\n\nsudo python3 - <<\'PYREMOTE\'\nfrom pathlib import Path\n\nenv_file = Path(\'/opt/rsa-cms/runtime/backend.env\')\nupdates = {\n    \'RSA_MEDIA_STORAGE_MODE\': \'__BUCKET_MODE__\',\n    \'RSA_MEDIA_S3_BUCKET\': \'__BUCKET_NAME__\',\n    \'RSA_MEDIA_MAX_UPLOAD_MB\': \'__MAX_UPLOAD_MB__\',\n    \'AWS_DEFAULT_REGION\': \'__REGION__\',\n    \'AWS_REGION\': \'__REGION__\',\n}\nlines = env_file.read_text(encoding=\'utf-8\').splitlines()\nseen = set()\nout = []\nfor line in lines:\n    stripped = line.strip()\n    if not stripped or stripped.startswith(\'#\') or \'=\' not in stripped:\n        out.append(line)\n        continue\n    key = stripped.split(\'=\', 1)[0]\n    if key in updates:\n        out.append(f\'{key}={updates[key]}\')\n        seen.add(key)\n    else:\n        out.append(line)\nfor key, value in updates.items():\n    if key not in seen:\n        out.append(f\'{key}={value}\')\nenv_file.write_text(\'\\n\'.join(out).rstrip() + \'\\n\', encoding=\'utf-8\')\nPYREMOTE\n\nsudo chmod 640 "$ENV_FILE"\nsudo systemctl restart rsa-cms-backend.service\nsleep 4\nsudo systemctl --no-pager --full status rsa-cms-backend.service || true\n\necho "runtime_env_media_lines:"\nsudo grep -E \'^(RSA_MEDIA_STORAGE_MODE|RSA_MEDIA_S3_BUCKET|RSA_MEDIA_MAX_UPLOAD_MB|AWS_DEFAULT_REGION|AWS_REGION)=\' "$ENV_FILE"\n\'@\n\n$remoteScript = $remoteScript.Replace(\'__BUCKET_MODE__\', \'s3\')\n$remoteScript = $remoteScript.Replace(\'__BUCKET_NAME__\', $BucketName)\n$remoteScript = $remoteScript.Replace(\'__MAX_UPLOAD_MB__\', $MaxUploadMb)\n$remoteScript = $remoteScript.Replace(\'__REGION__\', $Region)\n\n$ssh = Get-Command ssh -ErrorAction Stop\n& $ssh.Source -i $KeyPath "${SshUser}@${HostName}" $remoteScript\nif ($LASTEXITCODE -ne 0) { throw "remote EC2 media S3 env configuration failed" }\n\nWrite-Host "Batch 56A EC2 media S3 runtime env configuration completed."\n'

DOC = '# Batch 56A - S3 media storage setup/preflight\n\nThis package completes the storage-infrastructure side of Batch 56A after the local upload endpoint has already passed.\n\nScope:\n\n- Create or verify one private S3 bucket for RSA CMS admin media uploads.\n- Enable S3 Block Public Access.\n- Enable default SSE-S3 encryption.\n- Keep bucket versioning off/suspended for Free-Tier-first launch.\n- Optionally attach a narrow inline IAM policy to the EC2 instance role.\n- Configure EC2 runtime environment to use S3 mode.\n- Run an S3 write/read/delete smoke test.\n\nOut of scope:\n\n- No admin form integration. That is Batch 56B.\n- No CloudFront.\n- No Route 53/domain dependency.\n- No public-read bucket policy.\n- No S3 versioning, replication, advanced Storage Lens, lifecycle, or paid notification services.\n- No DynamoDB schema changes.\n\nRecommended bucket:\n\n```text\nrsa-cms-media-537765358118-ap-southeast-1\n```\n\nRecommended runtime env on EC2:\n\n```text\nRSA_MEDIA_STORAGE_MODE=s3\nRSA_MEDIA_S3_BUCKET=rsa-cms-media-537765358118-ap-southeast-1\nRSA_MEDIA_MAX_UPLOAD_MB=5\nAWS_DEFAULT_REGION=ap-southeast-1\nAWS_REGION=ap-southeast-1\n```\n\nIAM policy attached to the EC2 role is intentionally narrow:\n\n- `s3:GetBucketLocation`\n- `s3:ListBucket`\n- `s3:GetObject`\n- `s3:PutObject`\n- `s3:DeleteObject`\n\nOnly on the approved bucket and its objects.\n'


def write(path: Path, content: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8", newline="\n")
    print(f"[ok] wrote {path.relative_to(ROOT)}")


def main() -> None:
    write(ROOT / "backend" / "scripts" / "setup_media_s3_storage_56a.py", SETUP_SCRIPT)
    write(ROOT / "backend" / "scripts" / "check_media_s3_storage_56a.py", CHECK_SCRIPT)
    write(ROOT / "deploy" / "ec2" / "configure_media_s3_runtime_env_56a.ps1", EC2_ENV_PS1)
    write(ROOT / "docs" / "phase8_batch56a_s3_media_storage_setup.md", DOC)
    print("[done] batch56a-s3-media-storage-setup scripts/docs applied.")
    print("[done] No backend API code, frontend/admin form, DynamoDB schema, CloudFront, Route 53, or paid notification change.")


if __name__ == "__main__":
    main()
